```json
{
  "global": "Navigate to the wall art category on the department store website and apply a $25–$50 price range filter to display matching products.",
  "subtasks": [
    {
      "subtask": "Locate and open the wall art category",
      "atomics": [
        "Load the department store homepage",
        "Find the top-level navigation menu and identify a 'Home Decor', 'Art', or equivalent category",
        "Hover over or click the category to reveal subcategories and select 'Wall Art'"
      ]
    },
    {
      "subtask": "Apply the $25–$50 price range filter",
      "atomics": [
        "Locate the price filter widget in the left-hand facet panel or filter bar",
        "Set the minimum price input to 25",
        "Set the maximum price input to 50",
        "Submit or confirm the filter (click 'Apply', press Enter, or drag slider to target values)"
      ]
    },
    {
      "subtask": "Confirm filtered product listing is displayed",
      "atomics": [
        "Verify the product grid updates and shows wall art items",
        "Check that displayed prices fall within $25–$50",
        "Confirm the active filter badge or breadcrumb reflects the applied price range"
      ]
    }
  ],
  "global_atomics": [
    "Verify page state shows wall art category with $25–$50 price filter active and at least one result visible"
  ],
  "gold_actions": {
    "global": "Click through site navigation to Wall Art subcategory, then set price facet min=25 max=50 and confirm results render within that range.",
    "subtasks": [
      {
        "subtask": "Click 'Wall Art' in the site category hierarchy",
        "atomics": [
          "GET / and wait for homepage DOM to load",
          "Click the 'Home Decor' (or equivalent) top-nav link to expand the dropdown menu",
          "Click the 'Wall Art' link in the expanded subcategory list"
        ]
      },
      {
        "subtask": "Set price filter inputs to min=$25 and max=$50 and trigger filter application",
        "atomics": [
          "Locate the price range widget (slider or text inputs) in the left facet panel",
          "Type '25' into the minimum price field (or drag left slider handle to $25)",
          "Type '50' into the maximum price field (or drag right slider handle to $50)",
          "Click 'Apply' button or press Enter to fire the filter query"
        ]
      },
      {
        "subtask": "Read and validate the filtered product listing page",
        "atomics": [
          "Assert product card elements are present in the DOM",
          "Extract displayed price values and assert each is >= $25 and <= $50",
          "Assert the active-filter chip or breadcrumb text contains '$25 - $50'"
        ]
      }
    ],
    "global_atomics": [
      "Assert page URL contains wall-art category path and price filter query parameters (e.g., price_min=25&price_max=50) and product count > 0"
    ]
  }
}
```
